const msg = $input.first().json.message;
if (!msg) return [];

const chatType = msg.chat.type;
const text = msg.text || '';
let prompt = '';
let shouldGenerate = false;

// We will fetch the bot's username dynamically if possible or assume command syntax
if (chatType === 'private') {
    if (!text.startsWith('/')) {
        prompt = text;
        shouldGenerate = true;
    }
} else {
    // In groups, trigger on /generate, /gen, or mention
    if (text.startsWith('/generate ') || text.startsWith('/gen ')) {
        const parts = text.split(' ');
        parts.shift();
        prompt = parts.join(' ');
        shouldGenerate = true;
    } else if (text.includes('@') && text.toLowerCase().includes('bot')) {
        // Fallback matching for any bot mention
        const mentionMatch = text.match(/@\w+bot/i);
        if (mentionMatch) {
            prompt = text.replace(mentionMatch[0], '').trim();
            shouldGenerate = true;
        }
    }
}

return [{
    json: {
        chatId: msg.chat.id,
        messageId: msg.message_id,
        prompt: prompt.trim(),
        shouldGenerate: shouldGenerate
    }
}];

const responseData = $input.first().json;
const extractPromptNode = $node["Extract Prompt & Filter"].json;

if (!responseData.artifacts || !responseData.artifacts[0]) {
    throw new Error("No image returned from NVIDIA API. Response: " + JSON.stringify(responseData));
}

const base64Data = responseData.artifacts[0].base64;
const buffer = Buffer.from(base64Data, 'base64');

return {
  json: {
    chatId: extractPromptNode.chatId,
    messageId: extractPromptNode.messageId,
    prompt: extractPromptNode.prompt
  },
  binary: {
    data: {
      data: buffer,
      mimeType: 'image/png',
      fileName: 'generated_image.png'
    }
  }
};
